import { useCallback } from 'react';

import constFlaskURL from '../consts/constFlaskURL'

export const transformDataForTable = (data) => {
    if (!Array.isArray(data) || data.length === 0) 
    {
        return [];
    }

    return data.map(
        (item, index) => (
            {
                id: index + 1,
                ...item
            }
        )
    );
}

export const fetchTableData = () => { 
    const fetchTableData = useCallback(async () => {
        try {
            // const response = readRows('/roads');
            const response = await constFlaskURL.get('/roads');

            if (response.status === 200) {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } catch (err) {
            console.log(err);
        } 
    }, []);

    return { fetchTableData };
}
